mapper.update:
UPDATE orders
SET status = 'EXPIRED', updated_at = #{updatedAt}
WHERE id = #{id} AND status = 'PENDING_PAYMENT'

UPDATE orders
SET status = 'PAID', paid_at = #{paidAt}, updated_at = #{updatedAt}
WHERE id = #{id} AND user_id = #{userId} AND status = 'PENDING_PAYMENT'

mapper.select:
SELECT 
FROM orders
WHERE user_id = #{userId}
ORDER BY created_at DESC, id DESC
LIMIT #{limit} OFFSET #{offset}

SELECT id
FROM orders
WHERE status = 'PENDING_PAYMENT' AND expire_at < #{now}
ORDER BY expire_at ASC
LIMIT #{limit}
